let response = "Select a task to change its status:";
let index = 1;

for (const item of $input.all()) {
  response += `\n${index}. ${item.json['Task description']}`;
  index++;
}

return { response_text: response };

// קבלת המספר שהמשתמש הקליד (למשל "2") מהטריגר
const userInput = $('Telegram Trigger').first().json.message.text;
const selectedIndex = parseInt(userInput);

// קבלת כל המשימות (Items) שהגיעו מה-Supabase
const allTasks = $input.all();

// בדיקה אם המספר תקין וקיים ברשימה
if (selectedIndex > 0 && selectedIndex <= allTasks.length) {
  // שליפת המשימה הספציפית (מורידים 1 כי המערך מתחיל מ-0)
  const task = allTasks[selectedIndex - 1].json;

  return {
    selected_task_id: task.id,
    selected_task_name: task['Task description'],
    status: task['Task execution status']
  };
} else {
  return { error: "Selection out of range" };
}

