let response = "List of open tasks:\n\n";
let index = 1;

for (const item of $input.all()) {
  const taskName = item.json['Task description'] || 'No Description';
  const status = item.json['Task execution status'] || 'N/A';
  const deadline = item.json['Deadline'] || 'No Deadline';

  response += `${index}. ${taskName}\n`;
  response += `   Status: ${status}\n`;
  response += `   Deadline: ${deadline}\n\n`;

  index++;
}

return { response_text: response };

